module pe(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output [31:0] c
);

    reg [31:0] acc;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            acc <= 32'b0;
        end else begin
            acc <= acc + (a * b);
        end
    end

    assign c = acc;

endmodule
